const entrada = msg.payload || {};
const perguntaOriginal =
    entrada.pergunta ||
    (msg.req && msg.req.body && msg.req.body.pergunta) ||
    "";

const pergunta = String(perguntaOriginal).trim();
const texto = pergunta.toLowerCase();

function contemAlgumaPalavra(palavras) {
    return palavras.some((palavra) => texto.includes(palavra));
}

function escaparHtml(valor) {
    return String(valor)
        .replace(/&/g, "&amp;")
        .replace(/</g, "&lt;")
        .replace(/>/g, "&gt;")
        .replace(/"/g, "&quot;")
        .replace(/'/g, "&#039;");
}

let categoria = "Outros";
let resposta = "Não encontrei uma resposta específica para sua pergunta. Tente perguntar sobre prazo, documentos, horários, entrega, nota ou funcionamento do agente.";

if (contemAlgumaPalavra(["prazo", "entrega", "data", "quando", "blackboard"])) {
    categoria = "Prazo e entrega";
    resposta = "O prazo de entrega do trabalho é 28/05/2026 pelo Blackboard. A apresentação também será realizada conforme orientação da disciplina.";
} else if (contemAlgumaPalavra(["documento", "documentos", "relatório", "relatorio", "arquivo", "json", "html", "print", "prints"])) {
    categoria = "Documentação";
    resposta = "Os entregáveis são: fluxo do Node-RED exportado em JSON, arquivo HTML do formulário e relatório curto com objetivo, funcionamento, regras implementadas e prints.";
} else if (contemAlgumaPalavra(["horário", "horario", "aula", "apresentação", "apresentacao"])) {
    categoria = "Horários e apresentação";
    resposta = "A apresentação será feita na data definida pela disciplina, junto com a entrega do projeto. O grupo deve explicar o funcionamento do fluxo e a lógica de decisão.";
} else if (contemAlgumaPalavra(["funciona", "funcionamento", "agente", "node-red", "node red", "fluxo", "orquestrador"])) {
    categoria = "Funcionamento do agente";
    resposta = "O agente recebe uma pergunta pelo formulário, envia os dados para o Node-RED, analisa palavras-chave em um nó function e retorna uma resposta automática em HTML.";
} else if (contemAlgumaPalavra(["nota", "avaliação", "avaliacao", "critério", "criterio", "pontuação", "pontuacao"])) {
    categoria = "Critérios de avaliação";
    resposta = "A avaliação considera funcionamento correto do agente, clareza da lógica, uso correto do Node-RED, organização do fluxo, documentação e trabalho em equipe.";
}

msg.statusCode = 200;
msg.headers = {
    "Content-Type": "text/html; charset=utf-8"
};

msg.payload = `
<!DOCTYPE html>
<html lang="pt-BR">
<head>
  <meta charset="UTF-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1.0" />
  <title>Resposta do Agente</title>
  <style>
    * {
      box-sizing: border-box;
      font-family: Arial, Helvetica, sans-serif;
    }

    body {
      margin: 0;
      min-height: 100vh;
      display: flex;
      align-items: center;
      justify-content: center;
      background: linear-gradient(135deg, #f4f7fb 0%, #e8f1fb 100%);
      color: #172033;
      padding: 24px;
    }

    main {
      width: 100%;
      max-width: 720px;
      background: #ffffff;
      border: 1px solid #d9e2ef;
      border-radius: 18px;
      padding: 32px;
      box-shadow: 0 20px 50px rgba(15, 76, 129, 0.12);
    }

    .tag {
      display: inline-block;
      color: #0f4c81;
      background: #e8f1fb;
      border: 1px solid #c8dbef;
      padding: 8px 12px;
      border-radius: 999px;
      font-size: 13px;
      font-weight: 700;
      margin-bottom: 16px;
    }

    h1 {
      margin: 0 0 20px;
      font-size: 30px;
    }

    .card {
      border: 1px solid #d9e2ef;
      border-radius: 14px;
      padding: 18px;
      margin-bottom: 16px;
      background: #fbfdff;
    }

    .label {
      display: block;
      color: #5f6b7a;
      font-size: 13px;
      font-weight: 700;
      text-transform: uppercase;
      letter-spacing: 0.04em;
      margin-bottom: 6px;
    }

    p {
      margin: 0;
      line-height: 1.6;
    }

    a {
      display: inline-block;
      margin-top: 10px;
      color: #ffffff;
      background: #0f4c81;
      text-decoration: none;
      padding: 12px 16px;
      border-radius: 12px;
      font-weight: 700;
    }
  </style>
</head>
<body>
  <main>
    <span class="tag">Resposta automática gerada pelo agente</span>
    <h1>Resultado do atendimento</h1>

    <section class="card">
      <span class="label">Pergunta recebida</span>
      <p>${escaparHtml(pergunta || "Nenhuma pergunta informada")}</p>
    </section>

    <section class="card">
      <span class="label">Categoria identificada</span>
      <p>${escaparHtml(categoria)}</p>
    </section>

    <section class="card">
      <span class="label">Resposta do agente</span>
      <p>${escaparHtml(resposta)}</p>
    </section>

    <a href="/">Fazer nova pergunta</a>
  </main>
</body>
</html>
`;

return msg;
